package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Locator;import com.microsoft.playwright.Page;import com.microsoft.playwright.options.SelectOption;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP19CrearPedidoUnProductoPlaywrightTest extends BaseTestPlaywright {    @Test    void crearPedidoConUnProducto() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']").fill("camarero");        page.locator("input[name='password']").fill("123");        page.locator("button[type='submit']").click();        page.waitForLoadState();        page.locator("a:has-text('Crear pedido'), a:has-text('Crear Pedido')")                .first()                .click();        page.waitForLoadState();        Locator selectorProductos = page.locator("select").first();        assertTrue(                selectorProductos.count() > 0,                "No se encontró el selector de productos."        );        String productoSeleccionado =                selectorProductos.locator("option").nth(1).textContent();        selectorProductos.selectOption("1");        page.locator("input[type='number']").first().fill("1");        page.locator("button:has-text('Agregar')")                .first()                .click();        page.locator("button:has-text('Guardar Pedido')")                .first()                .click();        page.waitForLoadState();        String contenido = page.content();        assertTrue(                contenido.contains("Pedidos Actuales")                        || contenido.contains("Pendiente"),                "El pedido no aparece como pendiente o en pedidos actuales."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get("evidencias/HP19-crear-pedido-un-producto.png"))                        .setFullPage(true)        );    }}